import React from "react";
import "../styles.css";

function CourseCard({course}) {

  return (
    <div className="card">
      <h3>{course.title}</h3>

      <p>{course.platform}</p>

      <p>⭐ {course.rating}</p>

      <a href={course.url}>
        Перейти к курсу
      </a>
    </div>
  );
}

export default CourseCard;
